import json
import time
from typing import Any
import uuid
from datetime import datetime
import logging

from agent_framework import WorkflowEvent, WorkflowRunState, AgentResponseUpdate, AgentExecutorResponse, AgentResponse, Message

from ._utils import serialize_data
from .structs.request import AgentFrameworkRequest


# Access or store common data across different events
class MapperContext:
    # Input
    request: AgentFrameworkRequest

    # Generated
    # global
    response_id: str | None = None
    response_created_at: float | None = None

    # The last seen item id
    item_id: str | None = None
    output_index: int = 0

    # The last seen call_id for function calling
    call_id: str | None = None

    # The currently active executor id (set by executor_invoked / data events)
    executor_id: str | None = None

    # Track the last executor's response text for workflow output
    last_executor_output: str | None = None


def event_mapper(event_type: str):
    """Decorator to register an event mapper method for a specific event type string.
    
    Args:
        event_type: The event type string this mapper handles (e.g., "started", "executor_invoked")
        
    Returns:
        Decorator function that registers the mapper
    """
    def decorator(func):
        func._event_type = event_type
        return func
    
    return decorator

class EventMapper():
    
    def __init__(self):
        """Initialize the EventMapper and register all decorated mapper methods."""
        self._event_mappers: dict[str, Any] = {}
        
        # Scan all methods for event_mapper decorators and register them
        for attr_name in dir(self):
            attr = getattr(self, attr_name)
            if callable(attr) and hasattr(attr, '_event_type'):
                event_type = attr._event_type
                self._event_mappers[event_type] = attr
    
    @event_mapper("started")
    def _map_started_event(self, ctx: MapperContext, event: WorkflowEvent) -> list[dict]:
        ctx.response_id = str(uuid.uuid4())
        ctx.response_created_at = time.time()
        return [{
            "type": "response.created",
            "response":{
                "id": ctx.response_id,
                "created_at": ctx.response_created_at,
                "model": ctx.request.model,
            },
        }]

    @event_mapper("failed")
    def _map_failed_event(self, ctx: MapperContext, event: WorkflowEvent) -> list[dict]:
        return [{
            "type": "response.failed",
            "response":{
                "id": ctx.response_id,
                "created_at": ctx.response_created_at,
                "model": ctx.request.model,
                "error": {
                    "code": event.details.error_type,
                    "message": event.details.message,
                    "traceback": event.details.traceback,
                },
            },
        }]

    @event_mapper("output")
    def _map_output_event(self, ctx: MapperContext, event: WorkflowEvent) -> list[dict]:
        # In RC3, Agent-based executors emit "output" events with AgentResponseUpdate data
        # for streaming text. Route these through the agent response update handler
        # to produce text deltas instead of a raw workflow output.
        if isinstance(event.data, AgentResponseUpdate):
            return self._map_agent_response_update(ctx, event.data)

        # Custom executors may yield AgentResponse objects via ctx.yield_output().
        # Extract the text from their messages so the Playground renders it
        # as readable text instead of raw JSON.
        if isinstance(event.data, AgentResponse):
            text = self._extract_text_from_agent_response(event.data)
            if text is not None:
                ctx.last_executor_output = text
                return [{
                    "type": "response.workflow_output",
                    "output": text,
                }]

        serialized_data = None
        if event.data is not None:
            try:
                serialized_data = serialize_data(event.data)
            except Exception as e:
                logging.warning(f"Failed to serialize workflow output data: {e}")
                serialized_data = str(event.data)
        return [{
            "type": "response.workflow_output",
            "output": serialized_data,
        }]

    @event_mapper("status")
    def _map_status_event(self, ctx: MapperContext, event: WorkflowEvent) -> list[dict]:
        if event.state == WorkflowRunState.IN_PROGRESS:
            return [{
                "type": "response.in_progress",
                "response":{
                    "id": ctx.response_id,
                    "created_at": ctx.response_created_at,
                    "model": ctx.request.model,
                },
            }]
        return []
    
    @event_mapper("data")
    def _map_data_event(self, ctx: MapperContext, event: WorkflowEvent) -> list[dict]:
        if not isinstance(event.data, AgentResponseUpdate):
            return []
        events = []
        update = event.data
        logging.debug(f"[EventMapper] data event (AgentResponseUpdate) received, executor_id={event.executor_id}, contents={len(update.contents) if update.contents else 0}")
        if event.executor_id:
            ctx.executor_id = event.executor_id
        if not ctx.item_id:
            # Fallback if item_id not set
            ctx.item_id = f"exec_{event.executor_id}_{str(uuid.uuid4())[:8]}"

        message_item_id = ctx.item_id + "_message"
        
        for content in update.contents:
            logging.debug(f"[EventMapper] Processing content type: {content.type}")
            if content.type == "text":
                events.append({
                    "type":"response.output_text.delta",
                    "content_index":0,
                    "delta": content.text,
                    "item_id": message_item_id,
                    "logprobs":[],
                    "output_index":ctx.output_index,
                })
            elif content.type == "function_call":
                if content.call_id != ctx.call_id:
                    ctx.call_id = content.call_id
                    ctx.output_index += 1
                    item: dict[str, Any] = {
                            "type":"function_call",     
                            "arguments":"",
                            "call_id": ctx.call_id,
                            "name": content.name,
                            "id": content.call_id,
                            "status":"in_progress",
                    }
                    if ctx.executor_id:
                        item["executor_id"] = ctx.executor_id
                    events.append({
                        "type":"response.output_item.added",           
                        "output_index": ctx.output_index,
                        "item": item,
                    })
                
                # Handle arguments delta
                delta_args = ""
                if isinstance(content.arguments, str):
                    delta_args = content.arguments
                elif content.arguments:
                    # Serialize dictionary arguments
                    try:
                        delta_args = json.dumps(serialize_data(content.arguments))
                    except Exception as e:
                        logging.warning(f"Failed to serialize arguments: {e}")
                        delta_args = str(content.arguments)

                if delta_args:
                    events.append({
                        "type": "response.function_call_arguments.delta",
                        "output_index": ctx.output_index,
                        "item_id": ctx.call_id,
                        "delta": delta_args,
                    })

            elif content.type == "function_result":
                serialized_result = None
                try:
                    serialized_result = serialize_data(content.result)
                except Exception as e:
                    logging.warning(f"Failed to serialize function result: {e}")
                    serialized_result = str(content.result)

                result_event: dict[str, Any] = {
                    "type":"response.function_result.complete",           
                    "call_id": content.call_id,
                    "output_index": ctx.output_index,
                    "output": serialized_result,
                    "status":"completed",
                    "item_id": ctx.item_id,
                    "timestamp":datetime.now().isoformat(),
                }
                if ctx.executor_id:
                    result_event["executor_id"] = ctx.executor_id
                events.append(result_event)
        
        return events

    @event_mapper("executor_invoked")
    def _map_executor_invoked_event(self, ctx: MapperContext, event: WorkflowEvent) -> list[dict]:
        ctx.item_id = f"exec_{event.executor_id}_{str(uuid.uuid4())[:8]}"
        ctx.executor_id = event.executor_id
        ctx.output_index += 1

        events = []
        # Serialize event data for frontend display
        serialized_data = None
        if event.data is not None:
            try:
                serialized_data = serialize_data(event.data)
                logging.debug(f"[Executor] {event.executor_id} serialized data: {serialized_data}")
            except Exception as e:
                logging.warning(f"Failed to serialize event data: {e}")
                serialized_data = str(event.data)
        
        executor_item: dict[str, Any] = {
            "type": "executor_action",
            "id": ctx.item_id,
            "executor_id": event.executor_id,
            "status": "in_progress",
            "input": serialized_data,
        }
        
        events.append({
            "type": "response.output_item.added",
            "output_index": ctx.output_index,
            "item": executor_item,
        })
        events.append({
            "type": "response.output_item.added",
            "output_index": ctx.output_index,
            "item": {
                "type": "message",
                "id": ctx.item_id + "_message",
                "status": "in_progress",
                "role": "assistant",
                "content": [],
            }
        })
        events.append({
            "type": "response.content_part.added",
            "output_index": ctx.output_index,
            "item_id": ctx.item_id + "_message",
            "content_index": 0,
            "part":{
                "text":"",
                "type":"output_text"
            }
        })
        return events

    @event_mapper("executor_completed")
    def _map_executor_completed_event(self, ctx: MapperContext, event: WorkflowEvent) -> list[dict]:
        ctx.executor_id = None
        events = []
        # Extract clean output: prefer the executor's response text over raw data
        output_data = self._extract_executor_response_text(event.data, event.executor_id)
        if output_data is None:
            # Fallback: serialize the full data (for non-Agent executors)
            if event.data is not None:
                try:
                    output_data = serialize_data(event.data)
                    logging.debug(f"[Executor] {event.executor_id} serialized data: {output_data}")
                except Exception as e:
                    logging.warning(f"Failed to serialize event data: {e}")
                    output_data = str(event.data)

        # Track last executor output for workflow-level output
        ctx.last_executor_output = output_data

        executor_item: dict[str, Any] = {
            "type": "executor_action",
            "id": ctx.item_id,
            "executor_id": event.executor_id,
            "status": "completed",
            "output": output_data,
        }
        
        events.append({
            "type": "response.output_item.done",
            "output_index": ctx.output_index,
            "item": executor_item,
        })
        events.append({
            "type": "response.output_item.done",
            "output_index": ctx.output_index,
            "item": {
                "type": "message",
                "id": ctx.item_id + "_message",
                "status": "completed",
                "role": "assistant",
                "content": [],
            }
        })
        return events

    @event_mapper("executor_failed")
    def _map_executor_failed_event(self, ctx: MapperContext, event: WorkflowEvent) -> list[dict]:
        ctx.executor_id = None
        return [{
            "type": "response.output_item.done",
            "output_index": ctx.output_index,
            "item": {
                "type": "executor_action",
                "id": ctx.item_id,
                "executor_id": event.executor_id,
                "status": "failed",
                "error": serialize_data(event.data) if event.data else None,
            },
        }]

    @event_mapper("superstep_started")
    def _map_superstep_started_event(self, ctx: MapperContext, event: WorkflowEvent) -> list[dict]:
        return []

    @event_mapper("superstep_completed")
    def _map_superstep_completed_event(self, ctx: MapperContext, event: WorkflowEvent) -> list[dict]:
        return []

    def _map_agent_response_update(self, ctx: MapperContext, event: AgentResponseUpdate) -> list[dict]:
        item_id = event.message_id
        logging.debug(f"[EventMapper] AgentResponseUpdate received, message_id={item_id}, contents={len(event.contents) if event.contents else 0}")
        results = []
        if item_id and item_id != ctx.item_id:
            ctx.item_id = item_id
            ctx.output_index += 1
            results.append({
                "type":"response.output_item.added",           
                "output_index": ctx.output_index,
                "item":{
                    "type":"message",       
                    "id": ctx.item_id,
                    "content":[],
                    "role":"assistant",
                    "status":"in_progress"
                },
            })
            results.append({
                "type":"response.content_part.added",
                "output_index": ctx.output_index,
                "content_index": 0,
                "item_id": ctx.item_id,
                "part": {
                    "type":"output_text",
                    "text":"",
                }
            })
        
        for content in event.contents:
            if content.type == "function_call":
                is_same_call = ctx.call_id and content.call_id == ctx.call_id
                
                if is_same_call and content.arguments:
                    delta_args = ""
                    if isinstance(content.arguments, str):
                        delta_args = content.arguments
                    elif content.arguments:
                        try:
                            delta_args = json.dumps(serialize_data(content.arguments))
                        except Exception as e:
                            logging.warning(f"Failed to serialize arguments: {e}")
                            delta_args = str(content.arguments)
                    
                    if delta_args:
                        results.append({
                            "type": "response.function_call_arguments.delta",
                            "output_index": ctx.output_index,
                            "item_id": ctx.call_id,
                            "delta": delta_args,
                        })
                else:
                    if content.call_id != ctx.call_id:
                        ctx.call_id = content.call_id
                        ctx.output_index += 1
                    item: dict[str, Any] = {
                            "type":"function_call",     
                            "arguments":"",
                            "call_id": ctx.call_id,
                            "name": content.name,
                            "id": content.call_id,
                            "status":"in_progress",
                    }
                    if ctx.executor_id:
                        item["executor_id"] = ctx.executor_id
                    results.append({
                        "type":"response.output_item.added",           
                        "output_index": ctx.output_index,
                        "item": item,
                    })
                    if content.arguments:
                        initial_args = ""
                        if isinstance(content.arguments, str):
                            initial_args = content.arguments
                        elif content.arguments:
                            try:
                                initial_args = json.dumps(serialize_data(content.arguments))
                            except Exception as e:
                                logging.warning(f"Failed to serialize initial arguments: {e}")
                                initial_args = str(content.arguments)
                        
                        if initial_args:
                            results.append({
                                "type": "response.function_call_arguments.delta",
                                "output_index": ctx.output_index,
                                "item_id": ctx.call_id,
                                "delta": initial_args,
                            })
            elif content.type == "function_result":
                result_event: dict[str, Any] = {
                    "type":"response.function_result.complete",           
                    "call_id": content.call_id,
                    "output_index": ctx.output_index,
                    "output": serialize_data(content.result),
                    "status":"completed",
                    "item_id": ctx.item_id,
                    "timestamp":datetime.now().isoformat(),
                }
                if ctx.executor_id:
                    result_event["executor_id"] = ctx.executor_id
                results.append(result_event)

            elif content.type == "text":
                results.append(
                    {
                        "type":"response.output_text.delta",
                        "content_index":0,
                        "delta": content.text,
                        "item_id": ctx.item_id,
                        "output_index": ctx.output_index,
                    }
                )
            else:
                logging.warning("Unknown content type: %s", content.type)
        return results

    def _extract_text_from_agent_response(self, response: AgentResponse) -> str | None:
        """Extract readable text from an AgentResponse object.

        Used when custom executors yield AgentResponse via ctx.yield_output().
        """
        # AgentResponse exposes a .text convenience property
        text = getattr(response, "text", None)
        if text:
            return text

        # Fallback: iterate messages and collect text
        messages = getattr(response, "messages", None)
        if not messages:
            return None
        parts: list[str] = []
        for msg in messages:
            if not isinstance(msg, Message):
                continue
            if msg.contents:
                for c in msg.contents:
                    if getattr(c, "type", None) == "text" and hasattr(c, "text"):
                        parts.append(c.text)
            elif getattr(msg, "text", None):
                parts.append(msg.text)
        return "\n\n".join(parts) if parts else None

    def _extract_executor_response_text(self, event_data: Any, executor_id: str) -> str | None:
        """Extract the final response text for a specific executor from completed event data.

        For Agent executors, the data is typically a list containing:
        - AgentExecutorResponse with full_conversation (conversation history)
        - AgentResponseUpdate objects (streaming intermediates)

        We extract the last assistant message from the full_conversation
        whose author_name matches the executor_id.
        """
        if not isinstance(event_data, list):
            return None

        for item in event_data:
            if not isinstance(item, AgentExecutorResponse):
                continue
            conversation = getattr(item, "full_conversation", None)
            if not conversation:
                continue
            # Find the last assistant message from this executor
            for msg in reversed(conversation):
                if not isinstance(msg, Message):
                    continue
                role = msg.role.value if hasattr(msg.role, "value") else str(msg.role)
                if role != "assistant":
                    continue
                author = getattr(msg, "author_name", None)
                if author != executor_id:
                    continue
                # Extract text from contents
                if msg.contents:
                    texts = [c.text for c in msg.contents if getattr(c, "type", None) == "text" and hasattr(c, "text")]
                    if texts:
                        return "".join(texts)
                # Fall back to msg.text property
                text = getattr(msg, "text", None)
                if text:
                    return text
            # If no matching author_name, take the last assistant message
            for msg in reversed(conversation):
                if not isinstance(msg, Message):
                    continue
                role = msg.role.value if hasattr(msg.role, "value") else str(msg.role)
                if role != "assistant":
                    continue
                if msg.contents:
                    texts = [c.text for c in msg.contents if getattr(c, "type", None) == "text" and hasattr(c, "text")]
                    if texts:
                        return "".join(texts)
                text = getattr(msg, "text", None)
                if text:
                    return text

        return None

    def create_completion_event(self, ctx: MapperContext) -> list[dict]:
        """Create the response.completed event to emit after all workflow events are processed."""
        return [{
            "type": "response.completed",
            "response": {
                "id": ctx.response_id,
                "created_at": ctx.response_created_at,
                "model": ctx.request.model,
                "output": ctx.last_executor_output,
            },
        }]

    def _ensure_response_initialized(self, ctx: MapperContext) -> list[dict]:
        """Ensure response_id and response_created_at are set. Returns a response.created event if newly initialized."""
        if ctx.response_id is not None:
            return []
        ctx.response_id = str(uuid.uuid4())
        ctx.response_created_at = time.time()
        return [{
            "type": "response.created",
            "response": {
                "id": ctx.response_id,
                "created_at": ctx.response_created_at,
                "model": ctx.request.model,
            },
        }]

    def map_event(self, ctx: MapperContext, event: Any) -> list[dict]:
        """Map an Agent Framework event to OpenAI Responses API events"""
        logging.debug(f"[EventMapper] map_event called with event type: {type(event).__name__}")
        
        if isinstance(event, WorkflowEvent):
            mapper = self._event_mappers.get(event.type)
            if not mapper:
                logging.warning("Unknown workflow event type: %s", event.type)
                return []
            result = mapper(ctx, event)
        elif isinstance(event, AgentResponseUpdate):
            # For agents there is no "started" WorkflowEvent, so ensure a
            # response_id exists before mapping the first update.
            preamble = self._ensure_response_initialized(ctx)
            result = preamble + self._map_agent_response_update(ctx, event)
        else:
            logging.warning("Unknown event: %s", type(event))
            return []
        
        logging.debug(f"[EventMapper] Mapped to {len(result)} output events: {[e.get('type') for e in result]}")
        return result
    